class Solution {
    public String reverseParentheses(String s) {
        int openBrackets = 0;
        StringBuilder result = new StringBuilder();
        for (int i = s.length() - 1; i >= 0; i--) {
            char c = s.charAt(i);
            if (c == '(') {
                openBrackets++;
            } else if (c == ')') {
                openBrackets--;
            } else {
                result.append(c);
            }
            if (openBrackets == 0) {
                String reversed = result.reverse().toString();
                result.setLength(0);
                return reversed;
            }
        }
    }
}
```
